import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function SingleMetric({ label, value, unit, trend, thresholds }) {
  const { div, span } = tags;

  const getColor = (val) => {
    if (!thresholds) return '#00FF00';
    if (val >= thresholds.critical) return '#FF0000';
    if (val >= thresholds.warning) return '#FFB000';
    return '#00FF00';
  };

  const trendIcon = trend > 0 ? 'arrow-up' : trend < 0 ? 'arrow-down' : null;
  const trendColor = trend > 0 ? '#FF0000' : trend < 0 ? '#00FF00' : '#FFB000';

  return div({ class: css('term-panel _flex _col _aic _p4') },
    span({ class: css('_textsm _fgmuted _mb1') }, label),
    div({ class: css('_flex _aic _gap2') },
      span({ class: css('_text[2em] _fontbold term-glow'), style: `color: ${getColor(value)}` }, value),
      unit ? span({ class: css('_fgmuted') }, unit) : null,
      trendIcon ? icon(trendIcon, { size: '20', style: `color: ${trendColor}` }) : null
    )
  );
}

function InlineMetric({ label, value, unit, color }) {
  const { span } = tags;

  return span({ class: css('_flex _aic _gap1 _mono') },
    span({ class: css('_fgmuted') }, `${label}:`),
    span({ style: color ? `color: ${color}` : '' }, value),
    unit ? span({ class: css('_fgmuted') }, unit) : null
  );
}

function BlockMetric({ label, value, unit, history = [] }) {
  const { div, span } = tags;
  const braille = ['⣀', '⣄', '⣆', '⣇', '⣧', '⣷', '⣿'];

  const sparkline = () => {
    if (!history.length) return '';
    const min = Math.min(...history);
    const max = Math.max(...history);
    const range = max - min || 1;
    return history.slice(-15).map(v => {
      const idx = Math.floor(((v - min) / range) * (braille.length - 1));
      return braille[idx];
    }).join('');
  };

  return div({ class: css('term-panel _p2 _w[140px]') },
    span({ class: css('_textsm _fgmuted') }, label),
    div({ class: css('_flex _aic _gap1 _my1') },
      span({ class: css('_text[1.5em] _fontbold term-glow') }, value),
      unit ? span({ class: css('_fgmuted _textsm') }, unit) : null
    ),
    history.length ? span({ class: css('_textsm _fgmuted term-sparkline') }, sparkline()) : null
  );
}

function MetricGrid({ metrics, columns = 4 }) {
  const { div } = tags;

  return div({ class: css('_grid _gap2'), style: `grid-template-columns: repeat(${columns}, 1fr)` },
    ...metrics.map(m => BlockMetric(m))
  );
}

function MetricGauge({ variant = 'single', ...props }) {
  switch (variant) {
    case 'inline': return InlineMetric(props);
    case 'block': return BlockMetric(props);
    case 'grid': return MetricGrid(props);
    default: return SingleMetric(props);
  }
}
